import request from "supertest";
import express, { Express } from "express";

// Import the actual middleware and routes — real execution, no mocks at HTTP layer
import { authMiddleware } from "../../src/middleware/auth";
import { usersRouter } from "../../src/routes/users";

describe("GET /api/users — authentication enforcement", () => {
  let app: Express;

  beforeAll(() => {
    app = express();
    // Mount the users router WITH the auth middleware applied
    // This is the integration boundary the claim depends on
    app.use("/api/users", authMiddleware, usersRouter);
  });

  /**
   * Oracle: request with NO Authorization header must receive 401.
   * Falsification: if the endpoint accepts this request (status ≠ 401),
   * the claim is false.
   */
  it("returns 401 when Authorization header is absent", async () => {
    const response = await request(app).get("/api/users");

    // Oracle honesty: this assertion would fail if the endpoint accepted
    // the unauthenticated request (e.g., returned 200, 500, or any status ≠ 401)
    expect(response.status).toBe(401);
  });

  /**
   * Oracle: request with malformed Authorization header (missing 'Bearer' prefix)
   * must receive 401.
   * Falsification: if the endpoint accepts this malformed header (status ≠ 401),
   * the claim is false.
   */
  it("returns 401 when Authorization header lacks Bearer prefix", async () => {
    const response = await request(app)
      .get("/api/users")
      .set("Authorization", "InvalidTokenFormat");

    expect(response.status).toBe(401);
  });

  /**
   * Oracle: request with expired JWT token must receive 401.
   * Falsification: if the endpoint accepts this expired token (status ≠ 401),
   * the claim is false.
   */
  it("returns 401 when JWT token is expired", async () => {
    // Generate an expired token (exp < current time)
    const expiredPayload = {
      sub: "user123",
      iat: Math.floor(Date.now() / 1000) - 3600, // 1 hour ago
      exp: Math.floor(Date.now() / 1000) - 1800,  // 30 minutes ago (expired)
    };
    const expiredToken = Buffer.from(JSON.stringify(expiredPayload)).toString("base64");

    const response = await request(app)
      .get("/api/users")
      .set("Authorization", `Bearer ${expiredToken}`);

    expect(response.status).toBe(401);
  });

  /**
   * Oracle: request with JWT token signed by wrong key must receive 401.
   * Falsification: if the endpoint accepts this mis-signed token (status ≠ 401),
   * the claim is false.
   */
  it("returns 401 when JWT is signed with wrong key", async () => {
    // Payload with valid structure but signed with a different secret
    const misSignedPayload = {
      sub: "user123",
      iat: Math.floor(Date.now() / 1000),
      exp: Math.floor(Date.now() / 1000) + 3600,
    };
    // This is NOT signed with the server's actual secret
    const misSignedToken = Buffer.from(JSON.stringify(misSignedPayload)).toString("base64");

    const response = await request(app)
      .get("/api/users")
      .set("Authorization", `Bearer ${misSignedToken}`);

    expect(response.status).toBe(401);
  });
